                <circle cx="150" cy="100" r="60" fill="none" stroke="var(--chart-interest)" stroke-width="16" stroke-dasharray="${n.interestDashArray}" stroke-dashoffset="${n.interestOffset}" transform="rotate(-90 150 100)" />
